    var lCount = 0L
    var cCount = 0L
    var tCount = 0L
    var maxL = 0L
    var maxC = 0L
    var maxT = 0L

    // Precompute the number of 'T's after each position
    val tAfter = Array.ofDim[Long](n)
    var tAcc = 0L
    for (i <- n - 1 to 0 by -1) {
        if (s(i) == 'T') tAcc += 1
        tAfter(i) = tAcc
    }

    // Precompute the number of 'C's before each position and the potential 'L's
    val cBefore = Array.ofDim[Long](n)
    var cAcc = 0L
    for (i <- 0 until n) {
        if (s(i) == 'C') cAcc += 1
        cBefore(i) = cAcc
    }

    // Calculate the original count without any insertion
    var original = 0L
    for (i <- 0 until n) {
        if (s(i) == 'L') {
            original += cBefore(i) * tAfter(i)
        }
    }

    // Now find the best possible insertion
    // Case 1: Insert 'L' at position i (before s(i))
    var bestInsertL = 0L
    var currentL = 0L
    for (i <- 0 to n) {
        // The number of 'C's before i is cBefore(i min (n-1)) (if i == n, cBefore(n-1))
        val c = if (i < n) cBefore(i) else cBefore(n - 1)
        // The number of 'T's after i is tAfter(i min (n-1)) (if i == n, 0)
        val t = if (i < n) tAfter(i) else 0L
        val contribution = c * t
        if (contribution > bestInsertL) {
            bestInsertL = contribution
        }
    }

    // Case 2: Insert 'C' at position i
    var bestInsertC = 0L
    for (i <- 0 to n) {
        // The number of 'L's before i is lCount up to i-1
        var l = 0L
        for (j <- 0 until i) {
            if (s(j) == 'L') l += 1
        }
        // The number of 'T's after i is tAfter(i) if i < n else 0
        val t = if (i < n) tAfter(i) else 0L
        val contribution = l * t
        if (contribution > bestInsertC) {
            bestInsertC = contribution
        }
    }

    // Case 3: Insert 'T' at position i
    var bestInsertT = 0L
    for (i <- 0 to n) {
        // The number of 'L's before i is lCount up to i-1
        var l = 0L
        for (j <- 0 until i) {
            if (s(j) == 'L') l += 1
        }
        // The number of 'C's after i is (total C - cBefore(i)) if i < n else 0
        val totalC = cBefore(n - 1)
        val c = if (i < n) totalC - cBefore(i) else 0L
        val contribution = l * c
        if (contribution > bestInsertT) {
            bestInsertT = contribution
        }
    }

    // The best insertion is the maximum among the three cases
    val maxInsert = math.max(math.max(bestInsertL, bestInsertC), bestInsertT)

